// game-of-life.spec.ts
import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life - Next Generation", () => {
  it.todo("should return empty array for empty grid");
  it.todo("should kill a single live cell with no neighbors (underpopulation)");
  it.todo("should kill two adjacent live cells with only one neighbor each (underpopulation)");
  it.todo("should keep alive a live cell with two live neighbors (survival)");
  it.todo("should keep alive a live cell with three live neighbors (survival)");
  it.todo("should kill a live cell with four live neighbors (overpopulation)");
  it.todo("should bring a dead cell to life when it has exactly three live neighbors (reproduction)");
  it.todo("should transform a vertical blinker into a horizontal blinker");
  it.todo("should keep a block unchanged across generations (still life)");
});
